+export default {
+  OnnxEmbeddingsWasm,
+  getOnnxEmbeddingsWasm,
+  initOnnxEmbeddingsWasm,
+  isOnnxWasmAvailable,
+  isSIMDEnabled,
+  embed,
+  embedBatch,
+  similarity,
+  cosineSimilarity,
+  getStats,
+  shutdown,
+  resetStats,
+};

