+// Auto-initialization
+//=============================================================================
+
+// Try to initialize on module load (non-blocking)
+if (typeof process !== 'undefined' && process.env?.AGENTIC_FLOW_WASM !== 'false') {
+  initRuVectorWasm().catch(() => {
+    // Silent fail - will use JS fallbacks
+  });
+}
+
+export default {
+  isWasmSupported,
+  initRuVectorWasm,
+  isWasmInitialized,
+  generateIdentity,
+  signData,
+  verifySignature,
+  RuVectorHnswIndex,
+  RuVectorSemanticMatcher,
+};
